const items = $input.all();
const input = $('Execute Workflow Trigger').first().json;
const excludeAgentId = input.exclude_agent_id || null;
let result = "No se encontraron agentes activos.";

try {
  let agents = [];

  if (items.length > 0) {
    const firstItem = items[0].json;
    if (Array.isArray(firstItem)) {
      agents = firstItem.filter(a => a && a.id);
    } else if (firstItem && firstItem.id) {
      agents = items.map(item => item.json).filter(a => a && a.id);
    }
  }

  if (agents.length === 0) {
    return [{ json: { result } }];
  }

  // Exclude the previously assigned agent if provided
  let available = agents;
  if (excludeAgentId) {
    available = agents.filter(a => a.id !== excludeAgentId);
    // If all agents were excluded, fall back to all agents
    if (available.length === 0) {
      available = agents;
    }
  }

  // Select random agent
  const randomIndex = Math.floor(Math.random() * available.length);
  const selected = available[randomIndex];

  result = JSON.stringify({
    agent_id: selected.id,
    agent_name: selected.name || 'Agente',
    agent_email: selected.email || '',
    agent_role: selected.role || 'agent',
    total_active_agents: agents.length
  });
} catch (e) {
  result = "Error al asignar agente: " + e.message;
}

return [
  {
    json: {
      result: result
    }
  }
];
